<?php require_once '../../../includes/config.php'; require_once '../../../includes/db.php'; require_once '../../../includes/auth.php'; require_once '../../../includes/helpers.php'; require_role(['admin']); $pdo = get_pdo(); $page_title = 'Edit Mata Kuliah'; $id = isset($_GET['id']) ? (int)$_GET['id'] : 0; if (!$id) { flash('error', 'Mata kuliah tidak ditemukan'); redirect(APP_URL . '/admin/matkul/index.php'); exit; } $stmt = $pdo->prepare("SELECT * FROM mata_kuliah WHERE id_matkul = ?"); $stmt->execute([$id]); $matkul = $stmt->fetch(); if (!$matkul) { flash('error', 'Mata kuliah tidak ditemukan'); redirect(APP_URL . '/admin/matkul/index.php'); exit; } $errors = []; $form_data = ['kode_matkul' => $matkul['kode_matkul'], 'nama_matkul' => $matkul['nama_matkul'], 'sks' => $matkul['sks'], 'semester' => $matkul['semester'], 'jenis' => $matkul['jenis']]; if ($_SERVER['REQUEST_METHOD'] === 'POST') { if (empty($_POST['_csrf']) || !csrf_verify($_POST['_csrf'])) { $errors[] = 'CSRF token tidak valid'; } $form_data['nama_matkul'] = trim($_POST['nama_matkul'] ?? ''); $form_data['sks'] = (int)($_POST['sks'] ?? 3); $form_data['semester'] = (int)($_POST['semester'] ?? 1); $form_data['jenis'] = $_POST['jenis'] ?? 'wajib'; if (empty($form_data['nama_matkul'])) { $errors[] = 'Nama mata kuliah harus diisi'; } if ($form_data['sks'] < 1 || $form_data['sks'] > 6) { $errors[] = 'SKS harus antara 1-6'; } if (empty($errors)) { try { $stmt = $pdo->prepare("UPDATE mata_kuliah SET nama_matkul = ?, sks = ?, semester = ?, jenis = ? WHERE id_matkul = ?"); $stmt->execute([$form_data['nama_matkul'], $form_data['sks'], $form_data['semester'], $form_data['jenis'], $id]); flash('success', 'Mata kuliah berhasil diperbarui'); redirect(APP_URL . '/admin/matkul/index.php'); exit; } catch (Exception $e) { $errors[] = 'Error: ' . $e->getMessage(); } } } ?> <!DOCTYPE html> <html lang="id"> <head> <meta charset="UTF-8"> <meta name="viewport" content="width=device-width, initial-scale=1.0"> <title><?= h($page_title) ?> - SIAKAD Gallery</title> <link rel="stylesheet" href="<?= APP_URL ?>/assets/css/style.css"> <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.10.0/font/bootstrap-icons.css"> <style> .form-container { background: white; border-radius: 16px; padding: 32px; box-shadow: 0 2px 10px rgba(11, 30, 79, 0.06); max-width: 600px; } .form-group { margin-bottom: 20px; } .form-label { display: block; font-weight: 600; color: #0B1E4F; margin-bottom: 8px; font-size: 14px; } .form-control, .form-select { width: 100%; padding: 10px 14px; border: 1px solid #E4E7EE; border-radius: 8px; font-size: 14px; font-family: inherit; } .form-control:disabled { background: #F5F6FA; color: #6B7489; cursor: not-allowed; } .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; } .form-actions { display: flex; gap: 12px; margin-top: 32px; padding-top: 24px; border-top: 1px solid #E4E7EE; } .btn-secondary { padding: 10px 20px; border-radius: 8px; border: 1px solid #E4E7EE; background: white; color: #2C3A59; text-decoration: none; cursor: pointer; font-weight: 500; } .alert-danger { background: #FFEBEE; border: 1px solid #EF9A9A; color: #C62828; padding: 12px 16px; border-radius: 8px; margin-bottom: 20px; } </style> </head> <body> <div class="app-container"> <?php include '../../../includes/header.php'; ?> <div class="main-content"> <?php include '../../../includes/sidebar.php'; ?> <div class="content-area"> <h1 style="margin-bottom: 24px;"><?= h($page_title) ?></h1> <div class="form-container"> <?php if (!empty($errors)): ?> <div class="alert-danger"> <ul style="margin: 0; padding-left: 20px;"> <?php foreach ($errors as $error): ?> <li><?= h($error) ?></li> <?php endforeach; ?> </ul> </div> <?php endif; ?> <form method="POST"> <input type="hidden" name="_csrf" value="<?= csrf_token() ?>"> <div class="form-group"> <label class="form-label">Kode Mata Kuliah</label> <input type="text" class="form-control" value="<?= h($form_data['kode_matkul']) ?>" disabled> </div> <div class="form-group"> <label class="form-label">Nama Mata Kuliah <span style="color: #E04F5F;">*</span></label> <input type="text" name="nama_matkul" class="form-control" value="<?= h($form_data['nama_matkul']) ?>" maxlength="100" required> </div> <div class="form-row"> <div class="form-group"> <label class="form-label">SKS <span style="color: #E04F5F;">*</span></label> <input type="number" name="sks" class="form-control" value="<?= $form_data['sks'] ?>" min="1" max="6" required> </div> <div class="form-group"> <label class="form-label">Semester <span style="color: #E04F5F;">*</span></label> <input type="number" name="semester" class="form-control" value="<?= $form_data['semester'] ?>" min="1" max="8" required> </div> </div> <div class="form-group"> <label class="form-label">Jenis <span style="color: #E04F5F;">*</span></label> <select name="jenis" class="form-select" required> <option value="wajib" <?= $form_data['jenis'] === 'wajib' ? 'selected' : '' ?>>Wajib</option> <option value="pilihan" <?= $form_data['jenis'] === 'pilihan' ? 'selected' : '' ?>>Pilihan</option> </select> </div> <div class="form-actions"> <button type="submit" class="btn btn-primary"><i class="bi bi-check-circle"></i> Simpan Perubahan</button> <a href="<?= APP_URL ?>/admin/matkul/index.php" class="btn-secondary"><i class="bi bi-x-circle"></i> Batal</a> </div> </form> </div> </div> </div> </div> <?php include '../../../includes/footer.php'; ?> </body> </html>
